// v5.10.x strings (token-aware budgeting, backend retry, self-test, deployment presets, escalation consent, privacy).
$string['settings:backend_context_tokens'] = 'Backend-contextvenster (tokens)';
$string['settings:backend_context_tokens_desc'] = 'De maximale contextlengte (max_model_len) van uw AI-backend, in tokens. Stel in op 0 voor gehoste modellen met een groot venster (geen begrenzing). Wanneer ingesteld boven 0 (bijvoorbeeld 8192 op een zelfgehoste vLLM-backend), verkleint SOLA het tekenbudget van de systeemprompt hierboven zodat de prompt plus gereserveerde uitvoer en gespreksgeschiedenis in het venster passen, zelfs in token-dichte talen. Zie de wikipagina Deployment Sizing voor hoe dit zich verhoudt tot gelijktijdige gebruikers.';
$string['settings:backend_retry_attempts'] = 'Backend-herhaalpogingen';
$string['settings:backend_retry_attempts_desc'] = 'Hoe vaak een tijdelijke backendfout (HTTP 429 of 503) opnieuw moet worden geprobeerd voordat de student een fout te zien krijgt. Herhaalpogingen vinden alleen plaats voordat er responstekst is gestreamd, zodat de uitvoer nooit wordt gedupliceerd. Gericht op kleine zelfgehoste backends die verzoeken onder belasting weigeren. Stel in op 0 om uit te schakelen. Standaard 2.';
$string['settings:backend_retry_max_wait'] = 'Maximale wachttijd voor backend-herhaalpoging (seconden)';
$string['settings:backend_retry_max_wait_desc'] = 'Bovengrens, in seconden, voor hoe lang een Retry-After-header van de backend wordt gerespecteerd voordat opnieuw wordt geprobeerd. Wanneer de backend geen Retry-After verstuurt, gebruikt SOLA in plaats daarvan een korte exponentiële backoff. Standaard 5.';
$string['prompt:truncation_hint'] = 'OPMERKING: De volledige cursusinhoud kon deze beurt niet worden doorzocht vanwege lengtebeperkingen. Als de student vraagt naar iets dat u niet kunt vinden in de aangeleverde inhoud, zeg dan dat u niet de hele cursus kon doorzoeken en stel voor dat ze de specifieke pagina of activiteit openen waar het onderwerp wordt behandeld, in plaats van te stellen dat het ontbreekt in de cursus.';
$string['selftest:title'] = 'Backend-zelftest';
$string['selftest:intro'] = 'Voer een live-controle uit van uw geconfigureerde AI-backend: een kleine chat-heen-en-terug, automatische detectie van het contextvenster (max_model_len) en een vergelijking met uw instelling voor het backend-contextvenster, de ondergrens van het systeempromptbudget, en (wanneer RAG aan staat) een embedding-heen-en-terug. Netwerkoproepen worden alleen uitgevoerd wanneer u op Uitvoeren drukt.';
$string['selftest:run'] = 'Backend-zelftest uitvoeren';
