$string['profile:apply_self_hosted_small'] = 'Voorinstelling zelfgehost klein contextvenster toepassen';
$string['profile:apply_hosted_large'] = 'Standaardwaarden gehost groot contextvenster toepassen';
$string['profile:applied'] = 'De voorinstelling {$a} toegepast. De waarden staan nu in uw plug-in-instellingen.';
$string['profile:unknown'] = 'Onbekende implementatievoorinstelling.';
$string['profile:link'] = 'Pagina voor implementatievoorinstellingen';
$string['profile:link_desc'] = 'Open de pagina <a href="{$a}">Implementatievoorinstellingen</a> om een aanbevolen bundel instellingen toe te passen voor een gehoste of zelfgehoste backend.';
$string['settings:zendesk_require_consent'] = 'Toestemming vereisen vóór escalatie naar ondersteuning';
$string['settings:zendesk_require_consent_desc'] = 'Wanneer ingeschakeld (aanbevolen), escaleert SOLA een gesprek pas naar de Zendesk-ondersteuningsdesk nadat de lerende de toestemmingsmelding bij het eerste gebruik heeft geaccepteerd, die meldt dat het vragen om menselijke hulp het gesprek (inclusief naam en e-mail) deelt met ondersteuning. Schakel dit alleen uit als u die toestemming op een andere manier verkrijgt; met dit uitgeschakeld worden escalaties onmiddellijk verzonden. Heeft geen effect tenzij Zendesk-escalatie is ingeschakeld.';
$string['chat:escalation_needs_consent'] = 'Het lijkt erop dat hiervoor een lid van ons ondersteuningsteam nodig is. Om dit aan hen door te geven zou ik dit gesprek, inclusief uw naam en e-mailadres, met de ondersteuningsdesk moeten delen. U bent daar nog niet mee akkoord gegaan, dus ik heb niets verzonden. Als u menselijke hulp wenst, accepteer dan de melding over gegevensdeling voor deze assistent en vraag het opnieuw, of neem rechtstreeks contact op met ondersteuning.';
$string['privacy:metadata:email_optout'] = 'Voorkeuren voor e-mailafmelding per ontvanger (van welke e-mailtypen een ontvanger zich heeft afgemeld).';
$string['privacy:metadata:email_optout:email'] = 'Het e-mailadres van de ontvanger waarop de afmelding van toepassing is.';
$string['privacy:metadata:email_optout:optout_type'] = 'Het e-mailtype waarvoor de ontvanger zich heeft afgemeld.';
$string['privacy:metadata:email_optout:userid'] = 'De Moodle-gebruiker aan wie de afmelding toebehoort, indien bekend.';
$string['chat:consent_scroll_hint'] = 'Scrol naar beneden om de volledige kennisgeving te lezen voordat u doorgaat.';
$string['settings:rag_min_similarity'] = 'Minimale relevantie (cosinus)';
$string['settings:rag_min_similarity_desc'] = 'Verwijder opgehaalde fragmenten waarvan de cosinusgelijkenis met de vraag onder deze waarde ligt, zodat een vraag buiten het onderwerp of met weinig inhoud minder (of nul) passages invoegt in plaats van altijd op te vullen tot Top-K met zwakke overeenkomsten. Bereik 0 tot 1; 0 schakelt de poort uit. De juiste waarde hangt af van het embeddingmodel: 0.25 past bij text-embedding-3-small. Verhoog deze om strenger te zijn (minder, meer ter zake doende context), verlaag deze om toleranter te zijn.';
$string['settings:rag_currentpage_boost'] = 'Boost huidige pagina';
$string['settings:rag_currentpage_boost_desc'] = 'Een kleine bonus die wordt toegevoegd aan de relevantiescore van fragmenten van de pagina die de cursist op dit moment bekijkt, zodat vragen als "leg dit uit" de voorkeur geven aan de zichtbare pagina wanneer de scores dicht bij elkaar liggen. Alleen ordening: het dwingt een irrelevant paginafragment niet voorbij de poort voor minimale relevantie. Stel in op 0 om uit te schakelen.';
$string['settings:history_mode'] = 'Selectiemodus voor geschiedenis';
$string['settings:history_mode_desc'] = 'Hoe eerdere gespreksbeurten worden gekozen voordat ze naar het model worden verzonden. <strong>Semantisch</strong> behoudt alleen de recente beurten die relevant zijn voor de huidige vraag (en altijd de meest recente uitwisseling), zodat een verouderde, niet ter zake doende eerdere beurt de kosten niet opdrijft of het antwoord niet van koers brengt; het doet één extra embedding-aanroep per bericht. <strong>Recentheid</strong> behoudt de laatste "Max Conversation History"-paren ongeacht relevantie (het langbestaande gedrag, geen extra aanroep). Als embedding niet beschikbaar is, valt de semantische modus automatisch terug op recentheid.';
$string['settings:history_mode_semantic'] = 'Semantisch (relevante recente beurten)';
$string['settings:history_mode_recency'] = 'Recentheid (laatste N paren)';
$string['settings:history_semantic_minscore'] = 'Ondergrens relevantie geschiedenis (cosinus)';
$string['settings:history_semantic_minscore_desc'] = 'In de semantische geschiedenismodus wordt een eerdere beurt alleen behouden als de gelijkenis met de huidige vraag minstens deze waarde is (de meest recente uitwisseling wordt altijd behouden). Bereik 0 tot 1; modelafhankelijk. Verhoog om strenger te zijn (minder geschiedenis), verlaag om meer te behouden.';
$string['settings:history_candidates'] = 'Kandidatenvenster geschiedenis';
$string['settings:history_candidates_desc'] = 'In de semantische geschiedenismodus krijgen alleen de meest recente zoveel paren een relevantiescore (een kostengrens). Paren die ouder zijn dan dit venster worden niet verzonden. Houd deze waarde op of boven "Max Conversation History".';

// v5.11.0 - v6.2.0 strings (added 2026-06-10).
$string['settings:embed_provider_voyage'] = 'Voyage AI (voyage-3.5 — aanbevolen; +4 MTEB t.o.v. OpenAI 3-small, 4× context, meertalig)';
$string['settings:rerank_heading'] = 'RAG: Tweeledige opvraging (herrangschikking)';
$string['settings:rerank_heading_desc'] = 'Optionele tweede opvragingsfase: cosinus-gelijkenis selecteert de beste N kandidaatfragmenten (standaard 50), waarna een cross-encoder herrangschikker elk (vraag, fragment)-paar beoordeelt en de beste K fragmenten in de prompt worden opgenomen. Standaard uitgeschakeld; valt terug op enkelvoudige cosinus als de herrangschikker niet is geconfigureerd of mislukt.';
$string['settings:rerank_enabled'] = 'Tweeledige opvraging (Voyage rerank-2.5)';
$string['settings:rerank_enabled_desc'] = 'Wanneer ingeschakeld wordt RAG-opvraging tweeledig: cosinus-gelijkenis geeft de beste N kandidaten terug (standaard 50), waarna de Voyage rerank-2.5 cross-encoder elk beoordeelt en de beste K in de prompt worden opgenomen. Gepubliceerde verbeteringen: +15 Recall@10 enterprise, +39% NDCG BEIR. ~€0,05/MTok-facturering. Vereist <code>rerank_apikey</code> hieronder; valt soepel terug op enkelvoudige cosinus als herrangschikken mislukt of niet is geconfigureerd.';
$string['settings:rerank_apikey'] = 'Rerank API-sleutel';
$string['settings:rerank_apikey_desc'] = 'Voyage AI API-sleutel voor rerank-2.5. Leeg laten om de bovenstaande Embedding API-sleutel opnieuw te gebruiken (typische Voyage-implementaties delen één sleutel voor embed + rerank).';
$string['settings:rerank_model'] = 'Rerank-model';
$string['settings:rerank_model_desc'] = 'Standaard <code>rerank-2.5</code>. Nieuwere Voyage rerank-modellen kunnen hier worden opgegeven.';
$string['settings:rerank_apibaseurl'] = 'Rerank API basis-URL';
$string['settings:rerank_apibaseurl_desc'] = 'Overschrijf de Voyage rerank basis-URL. Leeg laten om de bovenstaande Embedding API basis-URL of de Voyage-standaard te gebruiken (<code>https://api.voyageai.com/v1</code>).';
$string['settings:rerank_candidates'] = 'Rerank kandidatenvenster';
$string['settings:rerank_candidates_desc'] = 'Hoeveel cosinus-gebaseerde beste N kandidaten de herrangschikkingsfase voeden. Standaard 50. Grotere vensters geven de herrangschikker meer materiaal om mee te werken voor geringe extra kosten (~10.000 tokens per herrangschikkingsoperatie).';
$string['settings:stt_selfhosted_heading'] = 'Zelfgehoste transcriptie (Whisper)';
$string['settings:stt_selfhosted_heading_desc'] = 'Voer spraak-naar-tekst uit op uw eigen hardware zonder kosten per minuut. Wijs SOLA naar een OpenAI-compatibele transcriptieserver: <code>whisper-server</code> Docker, <code>speaches</code> (faster-whisper) of <code>whisper.cpp</code>-server. Wanneer hier een server-URL is ingesteld, wordt dit het standaard STT-pad; kies een betaalde aanbieder bij de bovenstaande instelling Actieve STT-aanbieder om dit te overschrijven. Als de server zich op een privénetwerk of gewoon http bevindt, voeg dan ook de host toe aan de SSRF-vertrouwde eindpunten-allowlist in het gedeelte Beveiliging.';
$string['settings:stt_selfhosted_url'] = 'Zelfgehoste STT-server URL';
$string['settings:stt_selfhosted_url_desc'] = 'Basis-URL van de OpenAI-compatibele transcriptieserver, bijvoorbeeld <code>http://10.0.0.5:8000</code>. SOLA voegt automatisch <code>/v1/audio/transcriptions</code> toe; een volledig eindpuntpad wordt ook geaccepteerd. Leeg laten om zelfgehoste STT uit te schakelen.';
$string['settings:stt_selfhosted_model'] = 'Zelfgehoste STT-model';
$string['settings:stt_selfhosted_model_desc'] = 'Modelnaam die aan de server wordt doorgegeven, overeenkomend met het geladen Whisper-model — bijvoorbeeld <code>Systran/faster-whisper-small</code> voor speaches of <code>large-v3</code>. Leeg laten om <code>whisper-1</code> te verzenden, dat de meeste zelfgehoste servers accepteren of negeren.';
$string['settings:stt_selfhosted_apikey'] = 'Zelfgehoste STT API-sleutel';
$string['settings:stt_selfhosted_apikey_desc'] = 'Optioneel. De meeste zelfgehoste servers werken zonder sleutel achter een vertrouwd netwerk; stel dit alleen in als uw server een bearer-token vereist.';
$string['emergency:title'] = 'SOLA Noodcontroles';
