$string['prompt_debug_view:show_more'] = 'Meer vermeldingen weergeven';
$string['settings:mastery_classifier_provider'] = 'Classificatie-aanbieder';
$string['settings:mastery_classifier_provider_desc'] = 'Aanbieder-ID gebruikt voor de per-beurt beheersingclassificatie. Leeg laten om de standaard AI-aanbieder over te nemen. Standaard <code>openai</code> wordt gecombineerd met het <code>gpt-4o-mini</code>-classificatiemodel hieronder — de goedkoopste TIER 1-optie voor gestructureerde uitvoerclassificatie (~$220/maand besparing bij 100k MAU t.o.v. de chattier). Indien ingesteld, levert de rij in Vergelijkingsaanbieders met dit aanbieder-ID de API-sleutel, basis-URL en temperatuur.';
$string['settings:premium_escalation_heading'] = 'Premium escalatietier (A.10)';
$string['settings:premium_escalation_heading_desc'] = 'Optionele per-beurt routering naar een premium model (standaard Claude Opus 4.8) voor prompts waarbij de werkhors chattier zichtbaar moeite heeft — doorgaans meerstaps-wiskunde, informatica en wetenschappelijk redeneren. Beslecht door de A.10 bake-off van 2026-06-09: Opus 4.8 won met 14,97/15 vs. 12,68/15 van gpt-4o op moeilijke prompts. Twee triggerpaden: regex-overeenkomst op het gebruikersbericht, OF een cursusallowlist die elke beurt escaleert. Standaard uitgeschakeld. Bij ~5% escalatie wordt ~$700/maand bovenop de basisuitgaven voor chat verwacht bij 100k Saylor MAU.';
$string['settings:premium_escalation_enabled'] = 'Premium escalatieroutering inschakelen';
$string['settings:premium_escalation_enabled_desc'] = 'Wanneer ingeschakeld controleert de per-beurt router de triggerregexlijst en de cursusallowlist voor elke chatoproep; overeenkomende beurten worden naar de premium aanbieder gerouteerd. Valt terug op de werkhorstier als de premiumrij ontbreekt of niet kan worden geïnstantieerd. Beheerder-LLM-kiezer-overschrijvingen winnen altijd, zonder uitzondering.';
$string['settings:premium_escalation_provider'] = 'Premium aanbieder';
$string['settings:premium_escalation_provider_desc'] = 'Aanbieder-ID om premium oproepen via te routeren. Moet overeenkomen met een rij in Vergelijkingsaanbieders (zodat de API-sleutel, basis-URL en temperatuur van dezelfde plek komen die beheerders al beheren). Standaard <code>claude</code>.';
$string['settings:premium_escalation_model'] = 'Premium model';
$string['settings:premium_escalation_model_desc'] = 'Modelnaam doorgegeven aan de premium aanbieder. Standaard <code>claude-opus-4-8</code> conform het A.10 bake-off-oordeel.';
$string['settings:premium_escalation_triggers'] = 'Premium trigger-regexes';
$string['settings:premium_escalation_triggers_desc'] = 'Één PCRE-regex per regel (zonder scheidingstekens; hoofdletterongevoelige overeenkomst wordt automatisch toegepast). Regels die beginnen met # zijn opmerkingen. Leeg laten om de samengestelde standaardset uit de A.10 bake-off te gebruiken (meerstaps-STEM-markeringen: "derive", "prove that", "step by step", LaTeX-wiskunde, omheinde codeblokken, big-O, integralen, optimalisatie, enz.).';
$string['settings:premium_escalation_course_tags'] = 'Premium cursusallowlist';
$string['settings:premium_escalation_course_tags_desc'] = 'Één cursuskorte naam of idnummer-prefix per regel. Elke beurt in een overeenkomende cursus escaleert automatisch ongeacht de berichtregex (gebruik voor STEM-zware cursussen waar escalatie de standaard moet zijn). Overeenkomst is hoofdletterongevoelig prefix — "MATH" matcht MATH121, MATH205, enz.';
$string['settings:spend_cap_per_course_default'] = 'Standaard bestedingslimiet per cursus (USD)';
$string['settings:spend_cap_per_course_default_desc'] = 'Defensieve limiet toegepast op elke cursus die geen eigen bestedingslimiet per cursus heeft geconfigureerd. Stel in op bijv. <code>30</code> om de maandelijkse uitgaven van elke cursus te begrenzen op $30 zonder individuele cursussen af te hoeven stemmen. <code>0</code> = geen standaard (alleen sitewijde en per-cursus-overschrijvinglimieten gelden). Wanneer een cursus 80% / 95% / 100% van deze limiet overschrijdt, verzendt de bestaande spend-guard meldingspijplijn de beheerdermelding (ontvangerslijst: <code>spend_notify_emails</code>, terugval op sitebeheerders). Een specifieke cursus kan altijd zijn eigen plafond verhogen door een hogere per-cursus-overschrijving in te stellen.';
$string['settings:cost_anomaly_heading'] = 'Kostanomalie-detector (v6.0)';
$string['settings:cost_anomaly_heading_desc'] = 'Dagelijkse geplande taak (<code>cost_anomaly_check</code>) die de sitewijde SOLA-uitgaven van vandaag vergelijkt met de voortschrijdende mediaan van 7 dagen. Verstuurt een e-mail naar de ontvangerlijst <code>spend_notify_emails</code> (terugval op sitebeheerders) wanneer vandaag de geconfigureerde vermenigvuldiger × mediaan overschrijdt. Vangt drie storingsmodussen op die de bestaande 80% / 95% / 100%-bestedingsdrempels missen: (1) weggelopen cursus waarbij het absolute plafond niet wordt overschreden maar één cursus plotseling 10× het gebruikelijke volume genereert, (2) per ongeluk inschakelen van de premiumtier, (3) aanbieder-misrouting. Standaard uitgeschakeld; het SOLA-interne equivalent van de Redash-query in <code>.drafts/sola-redash-cost-anomaly-2026-06-09.md</code>.';
$string['settings:cost_anomaly_enabled'] = 'Kostanomalie-detector inschakelen';
$string['settings:cost_anomaly_enabled_desc'] = 'Wanneer ingeschakeld evalueert de dagelijkse geplande taak de uitgaven van vandaag ten opzichte van de voortschrijdende mediaan van 7 dagen en stuurt beheerders een e-mail bij een anomalie. De eerste 7 dagen na het inschakelen produceren een status <code>insufficient_history</code> (nog geen historische basislijn) en sturen nooit een melding. Per dag idempotent: een vlag in <code>config_plugins</code> voorkomt herhaalde e-mails als cron meerdere keren per dag wordt uitgevoerd.';
$string['settings:cost_anomaly_multiplier'] = 'Anomalie-vermenigvuldiger';
$string['settings:cost_anomaly_multiplier_desc'] = 'De uitgaven van vandaag moeten deze vermenigvuldiger × de mediaan van 7 dagen overschrijden om een melding te activeren. Standaard <code>2.0</code>. Verlaag naar <code>1.5</code> voor vroegere waarschuwingen (meer fout-positieven bij inschrijvingspieken). Verhoog naar <code>3.0</code> als het gebruik van Saylor grillig genoeg is dat 2× pieken normaal zijn.';
$string['task:cost_anomaly_check'] = 'SOLA dagelijkse kostenanomalie-controle';

// v6.4.0 signed policy bundle strings (added 2026-06-11).
$string['settings:policy_bundle_heading'] = 'Ondertekend beleidspakket (externe gedragsupdates)';
$string['settings:policy_bundle_heading_desc'] = 'Pas gedragsinstellingen (prompts, routering, escalatietriggers, RAG-afstemming, bestedingsbeleid) toe vanuit een cryptografisch ondertekend JSON-bestand zonder code-implementatie. Een dagelijkse geplande taak haalt de pakket-URL op, verifieert de Ed25519-handtekening met de onderstaande openbare sleutel en past de instellingen alleen toe als elke sleutel op de ingebouwde acceptatielijst staat en de pakketversie nieuwer is dan de laatste toegepaste. API-sleutels, URL\'s, webhooks en beveiligingsinstellingen kunnen nooit door een pakket worden ingesteld. Maak pakketten en onderteken ze met <code>admin/cli/policy_bundle_tool.php</code> (keygen, sign, verify, status, sync).';
$string['settings:policy_bundle_enabled'] = 'Synchronisatie van beleidspakket inschakelen';
$string['settings:policy_bundle_enabled_desc'] = 'Indien ingeschakeld haalt de dagelijkse taak ondertekende pakketten op en past ze toe. Standaard uitgeschakeld. Uitschakelen stopt onmiddellijk alle synchronisaties; reeds toegepaste instellingen behouden hun waarden.';
$string['settings:policy_bundle_url'] = 'URL van beleidspakket';
$string['settings:policy_bundle_url_desc'] = 'HTTPS URL van de ondertekende pakket-JSON (bijvoorbeeld een S3-object of GitHub raw URL). De URL ondergaat dezelfde SSRF-validatie als AI-provider-eindpunten; hosts op een privénetwerk of plain-http hebben een vermelding nodig in de acceptatielijst voor vertrouwde SSRF-eindpunten.';
$string['settings:policy_bundle_pubkey'] = 'Openbare sleutel van beleidspakket';
$string['settings:policy_bundle_pubkey_desc'] = 'Base64 Ed25519 openbare sleutel die wordt gebruikt om pakkethandtekeningen te verifiëren. Genereer het sleutelpaar met <code>policy_bundle_tool.php --keygen</code>; de privésleutel blijft bij de pakketauteur en mag nooit ergens worden geüpload.';
$string['settings:policy_bundle_status'] = 'Laatste synchronisatie';
$string['settings:policy_bundle_applied_version'] = 'toegepaste versie';
$string['task:policy_bundle_sync'] = 'SOLA-synchronisatie van ondertekend beleidspakket';
$string['policy_bundle:invalid'] = 'Beleidspakket geweigerd: {$a}';
$string['prompt_debug_view:retrieved_chunks'] = 'Opgehaalde fragmenten (RAG-selectie)';
$string['prompt_debug_view:retrieved_chunks_hint'] = 'De passages die de retriever voor deze vraag heeft geselecteerd, op rangvolgorde met hun relevantiescore en bron (cmid). Gebruik dit om te verifiëren dat het model de best passende cursusinhoud heeft ontvangen.';
$string['settings:avatar_animation_enabled'] = 'Avatar-animatie';
$string['settings:avatar_animation_enabled_desc'] = 'Animeer de gegenereerde SVG-avatar: knipperen in ruststand, plus mondbeweging gesynchroniseerd met tekst-naar-spraak-audio terwijl de assistent spreekt. Respecteert de voorkeur voor verminderde beweging van het apparaat van de leerling. Overschrijving per cursus voor A/B-meting: stel de configuratiewaarde avatar_animation_course_COURSEID in op 0 of 1.';
$string['analytics:exp_heading'] = 'Vergelijking van A/B-experiment';
$string['analytics:exp_desc'] = 'Vergelijk betrokkenheid tussen twee cursussen over het geselecteerde tijdbereik. Gebouwd voor per-cursus experimenten (bijvoorbeeld de avataranimatiemeting): plaats de overschrijving in één cursus, laat de andere als controle en lees hier het verschil.';
